package com.example.ppm.service;import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;import com.example.ppm.common.BusinessException;import com.example.ppm.dto.attachment.AttachmentResponse;import com.example.ppm.entity.Attachment;import com.example.ppm.entity.Task;import com.example.ppm.mapper.AttachmentMapper;import com.example.ppm.mapper.TaskMapper;import com.example.ppm.security.CurrentUserContext;import com.example.ppm.security.JwtUser;import org.springframework.beans.factory.annotation.Value;import org.springframework.stereotype.Service;import org.springframework.web.multipart.MultipartFile;import java.nio.file.*;import java.time.*;import java.util.*;
@Service public class AttachmentService {private final AttachmentMapper mapper;private final TaskMapper taskMapper;private final Path root;public AttachmentService(AttachmentMapper m,TaskMapper taskMapper,@Value("${app.upload-dir:./uploads}")String dir){mapper=m;this.taskMapper=taskMapper;root=Path.of(dir).toAbsolutePath();}
 /** taskId 非空时直接挂到该任务下（需校验任务归属当前用户） */
 public AttachmentResponse upload(MultipartFile f,String kind,Long taskId){if(taskId!=null)requireOwnTask(taskId);String mime=Optional.ofNullable(f.getContentType()).orElse("application/octet-stream");String actual=kind==null||kind.isBlank()?(mime.startsWith("image/")?"IMAGE":"FILE"):kind;if("IMAGE".equals(actual)&&(!mime.startsWith("image/")||f.getSize()>10*1024*1024))throw new BusinessException(400,"图片格式或大小不符合要求");if("FILE".equals(actual)&&f.getSize()>50*1024*1024)throw new BusinessException(400,"附件不能超过50MB");try{String ym=YearMonth.now().toString().replace('-','/');Path folder=root.resolve(ym);Files.createDirectories(folder);String ext=f.getOriginalFilename()!=null&&f.getOriginalFilename().contains(".")?f.getOriginalFilename().substring(f.getOriginalFilename().lastIndexOf('.')):"";String name=UUID.randomUUID()+ext;Files.copy(f.getInputStream(),folder.resolve(name));Attachment a=new Attachment();a.setTaskId(taskId);a.setKind(actual);a.setFileName(f.getOriginalFilename());a.setFilePath(ym+"/"+name);a.setUrl("/uploads/"+ym+"/"+name);a.setSize(f.getSize());a.setMimeType(mime);mapper.insert(a);return out(a);}catch(Exception e){throw new BusinessException(500,"文件保存失败");}}public List<AttachmentResponse> list(Long taskId){return mapper.selectList(new LambdaQueryWrapper<Attachment>().eq(Attachment::getTaskId,taskId)).stream().map(this::out).toList();}public void remove(Long id){Attachment a=mapper.selectById(id);if(a==null)throw new BusinessException(404,"附件不存在");try{Files.deleteIfExists(root.resolve(a.getFilePath()));}catch(Exception ignored){}mapper.deleteById(id);}public void bind(List<Long> ids,Long taskId){if(ids!=null)ids.forEach(id->{Attachment a=mapper.selectById(id);if(a!=null){a.setTaskId(taskId);mapper.updateById(a);}});}
 private void requireOwnTask(Long taskId){Task t=taskMapper.selectById(taskId);if(t==null)throw new BusinessException(404,"任务不存在");JwtUser u=CurrentUserContext.get();if(u==null||!u.userId().equals(t.getOwnerId()))throw new BusinessException(403,"无权限");}
 private AttachmentResponse out(Attachment a){return new AttachmentResponse(a.getId(),a.getKind(),a.getFileName(),a.getUrl(),a.getSize(),a.getMimeType());}}
